import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);

  const [search, setSearch] = useState("");

  const [searched, setSearched] = useState(false);

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed to fetch workers");
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1 style={styles.heading}>
          Find Workers
        </h1>

        {/* SEARCH */}

        <div style={styles.searchBox}>

          <input
            style={styles.input}
            placeholder="Search by work type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* RESULTS */}

        {searched && workers.length === 0 && (

          <p style={styles.noData}>
            No workers found
          </p>

        )}

        <div style={styles.grid}>

          {workers.map(worker => (

            <div
              key={worker._id}
              style={styles.card}
            >

              <h2 style={styles.name}>
                {worker.name}
              </h2>

              <p style={styles.text}>
                <strong>Skills:</strong>{" "}
                {worker.skills?.join(", ")}
              </p>

              <p style={styles.text}>
                <strong>Location:</strong>{" "}
                {worker.city}, {worker.area}
              </p>

              <p style={styles.text}>
                <strong>Phone:</strong>{" "}
                {worker.phone}
              </p>

              <p style={styles.price}>
                ₹ {worker.price}
              </p>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f7f9fc",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 70px"
  },

  heading: {
    marginBottom: "25px",
    color: "#111827"
  },

  searchBox: {
    display: "flex",
    gap: "15px",
    marginBottom: "35px"
  },

  input: {
    flex: 1,
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    fontSize: "15px"
  },

  searchBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "14px 24px",
    borderRadius: "10px",
    cursor: "pointer"
  },

  noData: {
    color: "#6b7280"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "22px",
    borderRadius: "14px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.05)"
  },

  name: {
    fontSize: "22px",
    marginBottom: "12px",
    color: "#111827"
  },

  text: {
    color: "#4b5563",
    marginBottom: "10px",
    lineHeight: "24px"
  },

  price: {
    marginTop: "15px",
    fontSize: "20px",
    color: "#2563eb",
    fontWeight: "bold"
  }

};
